-- ============================================================
-- EDUCAÇÃO ESPECIAL — LIMINARES e APOIO PEDAGÓGICO
-- Rode no SQL Editor do Supabase (Mapa / main). Ctrl+A -> Ctrl+Enter.
-- ============================================================
DROP TABLE IF EXISTS ee_liminar_aluno CASCADE;
CREATE TABLE ee_liminar_aluno (id serial PRIMARY KEY, aluno text, ra text, escola text, turma text, deficiencia text, laudo_sed text, liminar_atendida text, prof_apoio text);
ALTER TABLE ee_liminar_aluno DISABLE ROW LEVEL SECURITY;

DROP TABLE IF EXISTS ee_liminar_escola CASCADE;
CREATE TABLE ee_liminar_escola (id serial PRIMARY KEY, tipo text, escola text, liminares int, pap text);
ALTER TABLE ee_liminar_escola DISABLE ROW LEVEL SECURITY;

DROP TABLE IF EXISTS ee_apoio CASCADE;
CREATE TABLE ee_apoio (id serial PRIMARY KEY, tipo text, escola text, manha int, tarde int, total int, assej int);
ALTER TABLE ee_apoio DISABLE ROW LEVEL SECURITY;


CREATE OR REPLACE FUNCTION ee_liminar() RETURNS json LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $$
  SELECT json_build_object(
    'geral', (SELECT json_build_object('total',count(*),'atendidas',count(*) FILTER (WHERE upper(liminar_atendida)='SIM'),'escolas',count(distinct escola)) FROM ee_liminar_aluno),
    'escolas', coalesce((SELECT json_agg(json_build_array(tipo,escola,liminares,pap)) FROM (SELECT * FROM ee_liminar_escola ORDER BY tipo,escola) s),'[]'::json),
    'alunos',  coalesce((SELECT json_agg(json_build_array(aluno,ra,escola,turma,deficiencia,laudo_sed,liminar_atendida,prof_apoio)) FROM (SELECT * FROM ee_liminar_aluno ORDER BY escola,aluno) s),'[]'::json)
  );
$$;
CREATE OR REPLACE FUNCTION ee_apoio() RETURNS json LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $$
  SELECT json_build_object(
    'geral', (SELECT json_build_object('escolas',count(*),'manha',coalesce(sum(manha),0),'tarde',coalesce(sum(tarde),0),'total',coalesce(sum(total),0),'assej',coalesce(sum(assej),0)) FROM ee_apoio),
    'escolas', coalesce((SELECT json_agg(json_build_array(tipo,escola,manha,tarde,total,assej)) FROM (SELECT * FROM ee_apoio ORDER BY tipo,escola) s),'[]'::json)
  );
$$;
GRANT SELECT ON ee_liminar_aluno, ee_liminar_escola, ee_apoio TO anon, authenticated;
GRANT EXECUTE ON FUNCTION ee_liminar() TO anon, authenticated;
GRANT EXECUTE ON FUNCTION ee_apoio()   TO anon, authenticated;
